// --- Color parsing ---
// Parses hex color strings: "#RGB", "#RRGGBB", "#RRGGBBAA"

static UIColor* parseColor(const char* hex) {
    if (!hex || hex[0] != '#') return [UIColor blackColor];

    NSString *str = [NSString stringWithUTF8String:hex + 1]; // skip #
    unsigned long len = [str length];
    unsigned int r = 0, g = 0, b = 0, a = 255;

    if (len == 3) {
        // #RGB → #RRGGBB
        unsigned int vals[3];
        for (int i = 0; i < 3; i++) {
            NSString *ch = [str substringWithRange:NSMakeRange(i, 1)];
            [[NSScanner scannerWithString:ch] scanHexInt:&vals[i]];
            vals[i] = vals[i] * 17; // 0xF → 0xFF
        }
        r = vals[0]; g = vals[1]; b = vals[2];
    } else if (len == 6) {
        unsigned int val;
        [[NSScanner scannerWithString:str] scanHexInt:&val];
        r = (val >> 16) & 0xFF;
        g = (val >> 8) & 0xFF;
        b = val & 0xFF;
    } else if (len == 8) {
        unsigned int val;
        [[NSScanner scannerWithString:str] scanHexInt:&val];
        r = (val >> 24) & 0xFF;
        g = (val >> 16) & 0xFF;
        b = (val >> 8) & 0xFF;
        a = val & 0xFF;
    }

    return [UIColor colorWithRed:r/255.0 green:g/255.0 blue:b/255.0 alpha:a/255.0];
}

