void gox_set_root_view(long handle) {
    UIView *view = getView(handle);
    if (!view || !mainWindow) return;

    UIViewController *vc = mainWindow.rootViewController;
    if (!vc) {
        vc = [[UIViewController alloc] init];
        mainWindow.rootViewController = vc;
    }

    // Fill safe area
    view.translatesAutoresizingMaskIntoConstraints = NO;
    [vc.view addSubview:view];
    [NSLayoutConstraint activateConstraints:@[
        [view.topAnchor constraintEqualToAnchor:vc.view.safeAreaLayoutGuide.topAnchor],
        [view.bottomAnchor constraintEqualToAnchor:vc.view.safeAreaLayoutGuide.bottomAnchor],
        [view.leadingAnchor constraintEqualToAnchor:vc.view.safeAreaLayoutGuide.leadingAnchor],
        [view.trailingAnchor constraintEqualToAnchor:vc.view.safeAreaLayoutGuide.trailingAnchor],
    ]];
}

