void gox_set_font_weight(long handle, const char* weight) {
    UIView *view = getView(handle);
    if ([view isKindOfClass:[UILabel class]]) {
        UILabel *label = (UILabel *)view;
        CGFloat size = label.font.pointSize;
        NSString *w = [NSString stringWithUTF8String:weight];

        UIFontWeight fontWeight = UIFontWeightRegular;
        if ([w isEqualToString:@"bold"] || [w isEqualToString:@"700"]) {
            fontWeight = UIFontWeightBold;
        } else if ([w isEqualToString:@"600"]) {
            fontWeight = UIFontWeightSemibold;
        } else if ([w isEqualToString:@"500"]) {
            fontWeight = UIFontWeightMedium;
        } else if ([w isEqualToString:@"300"]) {
            fontWeight = UIFontWeightLight;
        } else if ([w isEqualToString:@"100"]) {
            fontWeight = UIFontWeightUltraLight;
        }

        label.font = [UIFont systemFontOfSize:size weight:fontWeight];
    }
}

