// --- App lifecycle ---

@interface GoxAppDelegate : UIResponder <UIApplicationDelegate>
@property (nonatomic, strong) UIWindow *window;
@end

// Declared in the Go side — called to render the initial view tree
extern void GoxRenderRoot(void);

@implementation GoxAppDelegate

- (BOOL)application:(UIApplication *)application
    didFinishLaunchingWithOptions:(NSDictionary *)launchOptions {

    self.window = [[UIWindow alloc] initWithFrame:[UIScreen mainScreen].bounds];
    self.window.backgroundColor = [UIColor whiteColor];
    self.window.rootViewController = [[UIViewController alloc] init];
    mainWindow = self.window;
    [self.window makeKeyAndVisible];

    // Call into Go to render the view tree
    GoxRenderRoot();

    return YES;
}

@end

void gox_run_app(int argc, char* argv[]) {
    @autoreleasepool {
        UIApplicationMain(argc, argv, nil, NSStringFromClass([GoxAppDelegate class]));
    }
}
